import{_ as t,o as a,c as r,a2 as s}from"./chunks/framework.Crpw6aS5.js";const m=JSON.parse('{"title":"Analytics et Insights","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/analytics.md","filePath":"fr/guide/analytics.md"}'),o={name:"fr/guide/analytics.md"};function n(i,e,l,u,d,c){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="analytics-et-insights" tabindex="-1">Analytics et Insights <a class="header-anchor" href="#analytics-et-insights" aria-label="Permalink to &quot;Analytics et Insights&quot;">​</a></h1><p>Nid offre des outils d&#39;analyse pour mieux comprendre vos habitudes email et identifier les opportunités de nettoyage.</p><hr><h2 id="heatmap-d-activite" tabindex="-1">Heatmap d&#39;activité <a class="header-anchor" href="#heatmap-d-activite" aria-label="Permalink to &quot;Heatmap d&#39;activité&quot;">​</a></h2><p>Une carte thermique visualise votre activité email sur une grille <strong>jour de la semaine × heure de la journée</strong>. Chaque cellule indique le nombre de mails reçus pendant ce créneau.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : heatmap d&#39;activité avec les jours en lignes et les heures en colonnes, colorée du bleu clair au bleu foncé</em></p></blockquote><p>Utilisez cette vue pour :</p><ul><li>Identifier vos pics de réception (ex. : lundi matin, mardi 14h)</li><li>Comprendre quand vous êtes le plus sollicité par email</li></ul><hr><h2 id="scores-d-encombrement" tabindex="-1">Scores d&#39;encombrement <a class="header-anchor" href="#scores-d-encombrement" aria-label="Permalink to &quot;Scores d&#39;encombrement&quot;">​</a></h2><p>Chaque expéditeur reçoit un <strong>score d&#39;encombrement</strong> calculé à partir de :</p><ul><li>Nombre de mails envoyés</li><li>Taille totale des mails</li><li>Nombre de mails non lus</li><li>Taux de lecture (mails lus / total)</li><li>Présence d&#39;un lien de désabonnement</li></ul><p>Plus le score est élevé, plus l&#39;expéditeur &quot;encombre&quot; votre boîte.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : tableau des scores d&#39;encombrement avec les colonnes expéditeur, nombre de mails, taille, taux de lecture, score</em></p></blockquote><hr><h2 id="suggestions-de-nettoyage" tabindex="-1">Suggestions de nettoyage <a class="header-anchor" href="#suggestions-de-nettoyage" aria-label="Permalink to &quot;Suggestions de nettoyage&quot;">​</a></h2><p>Nid génère automatiquement des <strong>suggestions de nettoyage</strong> basées sur l&#39;analyse de vos mails :</p><table tabindex="0"><thead><tr><th>Type de suggestion</th><th>Description</th></tr></thead><tbody><tr><td><strong>Expéditeurs en masse</strong></td><td>Expéditeurs qui envoient beaucoup de mails rarement lus</td></tr><tr><td><strong>Gros expéditeurs</strong></td><td>Expéditeurs dont les mails occupent beaucoup d&#39;espace</td></tr><tr><td><strong>Newsletters anciennes</strong></td><td>Newsletters non lues depuis longtemps</td></tr><tr><td><strong>Patterns de doublons</strong></td><td>Mails similaires en grand nombre</td></tr></tbody></table><p>Chaque suggestion indique le nombre de mails concernés et l&#39;espace récupérable.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : liste des suggestions de nettoyage avec le type, la description, et les boutons d&#39;action</em></p></blockquote><h3 id="ignorer-une-suggestion" tabindex="-1">Ignorer une suggestion <a class="header-anchor" href="#ignorer-une-suggestion" aria-label="Permalink to &quot;Ignorer une suggestion&quot;">​</a></h3><p>Si une suggestion n&#39;est pas pertinente, cliquez sur <strong>Ignorer</strong> pour la masquer. Elle ne réapparaîtra pas.</p><hr><h2 id="inbox-zero-tracker" tabindex="-1">Inbox Zero Tracker <a class="header-anchor" href="#inbox-zero-tracker" aria-label="Permalink to &quot;Inbox Zero Tracker&quot;">​</a></h2><p>Le tracker <strong>Inbox Zero</strong> mesure votre progression vers une boîte de réception vide :</p><ul><li><strong>Nombre de mails</strong> dans la boîte de réception</li><li><strong>Nombre de mails non lus</strong></li><li><strong>Historique</strong> : graphique montrant l&#39;évolution au fil du temps</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : graphique Inbox Zero montrant l&#39;évolution du nombre de mails dans la boîte de réception</em></p></blockquote><p>Un snapshot est enregistré automatiquement <strong>toutes les 6 heures</strong> pour alimenter l&#39;historique.</p><hr><h2 id="rapport-hebdomadaire" tabindex="-1">Rapport hebdomadaire <a class="header-anchor" href="#rapport-hebdomadaire" aria-label="Permalink to &quot;Rapport hebdomadaire&quot;">​</a></h2><p>Chaque <strong>lundi</strong>, un rapport hebdomadaire est automatiquement généré pour chaque compte Gmail :</p><ul><li>Nombre de mails reçus, archivés et supprimés pendant la semaine</li><li>Top expéditeurs de la semaine</li><li>Règles exécutées et espace libéré</li><li>Évolution par rapport à la semaine précédente</li></ul><p>Le rapport est envoyé comme <strong>notification in-app</strong> et peut être consulté depuis la page <strong>Insights</strong>.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page Insights avec le rapport hebdomadaire (résumé chiffré + graphiques)</em></p></blockquote><hr><h2 id="cache-des-analytics" tabindex="-1">Cache des analytics <a class="header-anchor" href="#cache-des-analytics" aria-label="Permalink to &quot;Cache des analytics&quot;">​</a></h2><p>Les données d&#39;analytics sont calculées à la demande et mises en cache pendant <strong>15 minutes</strong> dans Redis pour des performances optimales.</p>',37)])])}const g=t(o,[["render",n]]);export{m as __pageData,g as default};
